fn process_create_associated_token_account(
    program_id: &Pubkey, accounts: &[AccountInfo], create_mode: CreateMode,
) -> ProgramResult {
    let (associated_token_address, bump_seed) = get_associated_token_address_and_bump_seed_internal(
        wallet_account_info.key, spl_token_mint_info.key, program_id, spl_token_program_id);
    if associated_token_address != *associated_token_account_info.key {
        return Err(ProgramError::InvalidSeeds);
    }

    if create_mode == CreateMode::Idempotent && associated_token_account_info.owner == spl_token_program_id {
        return Ok(());
    }

    create_pda_account(funder_info, &Rent::get()?, account_len, spl_token_program_id,
        system_program_info, associated_token_account_info, associated_token_account_signer_seeds)?;
    Ok(())
}
